import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import Navbar from '../components/shared/Navbar';
import { chatAPI } from '../utils/api';
import { useAuth } from '../context/AuthContext';
import { useSocket } from '../context/SocketContext';
import { format } from 'date-fns';
import toast from 'react-hot-toast';

export default function ChatPage() {
  const { userId: otherUserIdParam } = useParams();
  const { user } = useAuth();
  const { socket, onlineUsers } = useSocket();
  const navigate = useNavigate();

  const [conversations, setConversations] = useState([]);
  const [messages, setMessages] = useState([]);
  const [activeChat, setActiveChat] = useState(otherUserIdParam || null);
  const [message, setMessage] = useState('');
  const [typing, setTyping] = useState(false);
  const [otherTyping, setOtherTyping] = useState(false);
  const [loadingMsgs, setLoadingMsgs] = useState(false);
  const messagesEndRef = useRef(null);
  const typingTimeoutRef = useRef(null);

  const scrollToBottom = () => messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });

  useEffect(() => {
    chatAPI.getConversations().then(r => setConversations(r.data.data)).catch(() => {});
  }, []);

  useEffect(() => {
    if (!activeChat) return;
    setLoadingMsgs(true);
    chatAPI.getConversation(activeChat)
      .then(r => setMessages(r.data.data))
      .finally(() => setLoadingMsgs(false));
  }, [activeChat]);

  useEffect(() => { scrollToBottom(); }, [messages]);

  useEffect(() => {
    if (!socket || !user || !activeChat) return;

    socket.emit('chat:join', { userId: user.id, otherUserId: activeChat });

    const onMessage = (msg) => {
      setMessages(prev => [...prev, msg]);
    };
    const onTyping = ({ senderId, isTyping }) => {
      if (senderId === activeChat) setOtherTyping(isTyping);
    };

    socket.on('chat:message', onMessage);
    socket.on('chat:typing', onTyping);

    return () => {
      socket.off('chat:message', onMessage);
      socket.off('chat:typing', onTyping);
    };
  }, [socket, user, activeChat]);

  const sendMessage = () => {
    if (!message.trim() || !activeChat) return;
    socket?.emit('chat:message', { senderId: user.id, receiverId: activeChat, message: message.trim() });
    // Optimistic update
    setMessages(prev => [...prev, {
      _id: Date.now(), sender: { _id: user.id, name: user.name }, receiver: activeChat,
      message: message.trim(), timestamp: new Date(), isRead: false,
    }]);
    setMessage('');
  };

  const handleTyping = (val) => {
    setMessage(val);
    if (!socket || !activeChat) return;
    socket.emit('chat:typing', { senderId: user.id, receiverId: activeChat, isTyping: true });
    clearTimeout(typingTimeoutRef.current);
    typingTimeoutRef.current = setTimeout(() => {
      socket.emit('chat:typing', { senderId: user.id, receiverId: activeChat, isTyping: false });
    }, 1500);
  };

  const openConversation = (conv) => {
    const otherId = conv.otherUser?._id;
    setActiveChat(otherId);
    navigate(`/chat/${otherId}`, { replace: true });
  };

  return (
    <div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column' }}>
      <Navbar />
      <div style={{ flex: 1, display: 'flex', overflow: 'hidden', height: 'calc(100vh - 64px)' }}>

        {/* ── Sidebar: Conversations ── */}
        <div style={{
          width: 300, borderRight: '1px solid var(--border)',
          display: 'flex', flexDirection: 'column', flexShrink: 0,
          background: 'var(--bg-secondary)',
        }}>
          <div style={{ padding: '16px', borderBottom: '1px solid var(--border)' }}>
            <h3 style={{ fontWeight: 700, fontSize: 16 }}>Messages</h3>
          </div>
          <div style={{ flex: 1, overflowY: 'auto' }}>
            {conversations.length === 0 ? (
              <div style={{ padding: 24, textAlign: 'center', color: 'var(--text-muted)', fontSize: 13 }}>
                No conversations yet
              </div>
            ) : conversations.map(conv => {
              const isActive = conv.otherUser?._id === activeChat;
              const isOnline = onlineUsers.has(conv.otherUser?._id);
              return (
                <div key={conv._id} onClick={() => openConversation(conv)}
                  style={{
                    padding: '14px 16px', cursor: 'pointer', borderBottom: '1px solid var(--border)',
                    background: isActive ? 'var(--bg-elevated)' : 'transparent',
                    transition: 'background 0.15s',
                  }}>
                  <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
                    <div style={{ position: 'relative' }}>
                      <div style={{
                        width: 38, height: 38, borderRadius: '50%', background: 'var(--accent-dim)',
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        color: 'var(--accent)', fontWeight: 700, fontSize: 13,
                      }}>
                        {conv.otherUser?.name?.split(' ').map(n => n[0]).join('').slice(0, 2)}
                      </div>
                      <span style={{
                        position: 'absolute', bottom: 0, right: 0,
                        width: 10, height: 10, borderRadius: '50%',
                        background: isOnline ? 'var(--success)' : 'var(--text-muted)',
                        border: '2px solid var(--bg-secondary)',
                      }} />
                    </div>
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ fontWeight: 600, fontSize: 14 }}>{conv.otherUser?.name}</div>
                      <div style={{ fontSize: 12, color: 'var(--text-muted)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                        {conv.lastMessage?.message?.substring(0, 35)}...
                      </div>
                    </div>
                    {conv.unreadCount > 0 && (
                      <span style={{
                        background: 'var(--accent)', color: '#fff',
                        borderRadius: '50%', width: 18, height: 18,
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        fontSize: 10, fontWeight: 700, flexShrink: 0,
                      }}>{conv.unreadCount}</span>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* ── Chat Area ── */}
        {activeChat ? (
          <div style={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
            {/* Chat Header */}
            <div style={{ padding: '12px 20px', borderBottom: '1px solid var(--border)', display: 'flex', alignItems: 'center', gap: 12, background: 'var(--bg-secondary)' }}>
              <div style={{ width: 36, height: 36, borderRadius: '50%', background: 'var(--accent-dim)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--accent)', fontWeight: 700, fontSize: 13 }}>
                {activeChat.substring(0, 2).toUpperCase()}
              </div>
              <div>
                <div style={{ fontWeight: 600, fontSize: 14 }}>Conversation</div>
                <div style={{ fontSize: 12, color: onlineUsers.has(activeChat) ? 'var(--success)' : 'var(--text-muted)' }}>
                  {onlineUsers.has(activeChat) ? '● Online' : '○ Offline'}
                </div>
              </div>
            </div>

            {/* Messages */}
            <div style={{ flex: 1, overflowY: 'auto', padding: '20px', display: 'flex', flexDirection: 'column', gap: 8 }}>
              {loadingMsgs ? (
                <div style={{ textAlign: 'center', color: 'var(--text-muted)' }}>Loading...</div>
              ) : messages.map((msg, i) => {
                const isMine = msg.sender?._id === user.id || msg.sender === user.id;
                return (
                  <div key={msg._id || i} style={{ display: 'flex', justifyContent: isMine ? 'flex-end' : 'flex-start' }}>
                    <div>
                      <div className={`chat-bubble ${isMine ? 'sent' : 'received'}`}>{msg.message}</div>
                      <div style={{ fontSize: 10, color: 'var(--text-muted)', marginTop: 2, textAlign: isMine ? 'right' : 'left', paddingLeft: isMine ? 0 : 4, paddingRight: isMine ? 4 : 0 }}>
                        {format(new Date(msg.timestamp), 'h:mm a')}
                        {isMine && <span style={{ marginLeft: 4 }}>{msg.isRead ? '✓✓' : '✓'}</span>}
                      </div>
                    </div>
                  </div>
                );
              })}
              {otherTyping && (
                <div style={{ display: 'flex', gap: 4, alignItems: 'center', color: 'var(--text-muted)', fontSize: 12 }}>
                  <div style={{ display: 'flex', gap: 3 }}>
                    {[0, 1, 2].map(i => (
                      <span key={i} style={{ width: 6, height: 6, borderRadius: '50%', background: 'var(--text-muted)', display: 'inline-block', animation: `pulse 1s ease ${i * 0.2}s infinite` }} />
                    ))}
                  </div>
                  typing...
                </div>
              )}
              <div ref={messagesEndRef} />
            </div>

            {/* Input */}
            <div style={{ padding: '12px 16px', borderTop: '1px solid var(--border)', display: 'flex', gap: 10, background: 'var(--bg-secondary)' }}>
              <input
                className="form-input"
                style={{ flex: 1 }}
                placeholder="Type a message..."
                value={message}
                onChange={e => handleTyping(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && !e.shiftKey && (e.preventDefault(), sendMessage())}
              />
              <button className="btn btn-primary" onClick={sendMessage} disabled={!message.trim()}>Send</button>
            </div>
          </div>
        ) : (
          <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', flexDirection: 'column', gap: 12, color: 'var(--text-muted)' }}>
            <div style={{ fontSize: 48 }}>💬</div>
            <h3 style={{ color: 'var(--text-secondary)' }}>Select a conversation</h3>
            <p style={{ fontSize: 14 }}>Choose a chat from the sidebar to start messaging</p>
          </div>
        )}
      </div>
    </div>
  );
}
